        CAN_METAMORPHOSE_OTHER_PEOPLE_S_AND_OF_COURSE                          = 6766,  -- % can metamorphose other people's % and %. Of course, it can only affect those that were made from the same %.
        THERE_ARE_TWO_TYPES_OF_METAMORPHOSES_WHICH_ARE                         = 6767,  -- There are two types of metamorphoses, which are: 1: Make into sack / Make into pearl 2: Kick.
