        AS_SUCH_IT_IS_IMPERATIVE_THAT_THE_OPERATOR                             = 7329,  -- As such, it is imperative that the operator exercise utmost caution to maintain the proper elemental balance at all times. In other words, fewell must be added in proper proportions, but with the contents of the furnace in a constant state of flux, this is no small task.
        FAILURE_TO_MAINTAIN_EQUILIBRIUM_MAY_RESULT_IN_EXPLOSIONS               = 7330,  -- Failure to maintain equilibrium may result in explosions, implosions, spontaneous combustions, or other unexpected and unpleasant results. Make no mistake: synergy is not a science for the faint of heart.
        FORTUNATELY_THERE_IS_GOOD_NEWS_THE_SYNERGY_FURNACE                     = 7331,  -- Fortunately, there is good news. The synergy furnace, you see, is designed to allow for manipulation by multiple operators at once.
        COMBINE_YOUR_KNOWLEDGE_AND_SKILL_WITH_THAT_OF                          = 7332,  -- Combine your knowledge and skill with that of your colleagues, master the process of maintaining equilibrium, and there is simply no limit to the wonders you may materialize. Truly a case of the whole being greater than the sum of its parts!
