        WHAT_YOU_VE_FORGOTTEN_WHICH_MATERIALS_YOU_NEED                         = 7343,  -- What? You've forgotten which materials you need? Tsk tsk. Ah well, you wouldn't be the first absent-minded synergist. Now listen carefully this time...
        STUPENDOUS_CAN_HARDLY_WAIT_TO_KICK_START_YOUR                          = 7344,  -- Stupendous! Can hardly wait to kick-start your career as a synergist, I see. Well, who am I to keep you waiting any longer?
        AND_THERE_YOU_HAVE_IT_YOUR_VERY_OWN                                    = 7345,  -- And there you have it! Your very own %, designed to be compatible with any synergy furnace. And as an added bonus to commemorate the birth of a new synergist, your first fill-up of fewell is on the house!
