        THEIR_TALENT_AT_MAKING_PROFIT_IS_INCOMPARABLE_BUT                      = 7694,  -- Their talent at making profit is incomparable, but their sense of duty is somewhat lacking. In fact, even their officials can be troublesome. For the sake of your mission's success, try to be patient.
        AH_YOU_VE_BROUGHT_THE_GOOD_WORK                                        = 7695,  -- Ah, you've brought the %. Good work.
        I_WILL_HAVE_RIAULT_MAKE_A_BRIEF_OF                                     = 7696,  -- I will have Riault make a brief of the information we've been able to assemble on Bastokan technology. Riault, if you please.
        AH_YOU_HAVE_RETURNED_WHAT_DID_YOU_FIND                                 = 7697,  -- Ah, you have returned. What did you find? Hmm...I see. I am glad you made it back safely.
        RIAULT_WILL_WRITE_DOWN_THE_DETAILS_OF_YOUR                             = 7698,  -- Riault will write down the details of your investigation. Please tell him what you have seen.
        SIGH_OH_WHEN_WILL_WE_BE_ALLOWED_TO                                     = 7699,  -- <Sigh> Oh, when will we be allowed to go back to San d'Oria, I wonder.
