        HOW_DARE_A_SIMPLE_CITIZEN_SPEAK_THAT_WAY                               = 9160,  -- How dare a simple citizen speak that way to a senator!
        WE_ELL_I_SUPPOSE_IT_S_ABOUT_TIME                                       = 9161,  -- We-ell... I suppose it's about time I took this fellow before the president and had him confess to his crimes. You don't mind, do you? After all, it is my duty.
        PRESIDENT_KARST_IS_SO_INTIMIDATING_I_D_JUST                            = 9162,  -- President Karst is so intimidating... I'd just break down and tell him everything.
