        WHEN_A_PLAYER_S_INVENTORY_EXCEEDS_THE_MAXIMUM                          = 9434,  -- When a player's inventory exceeds the maximum capacity, any temporary item found will simply be discarded. You can speak to me to borrow or return the shovel at any time.
        BORROW_THE_YES_NO                                                      = 9435,  -- Borrow the %? Yes. No.
