        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                       = 9438,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                                = 9439,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                                = 9440,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                              = 9441,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                  = 9442,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                         = 9443,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                            = 9444,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                         = 9445,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                = 9446,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                              = 9447,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                      = 9448,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                  = 9449,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                      = 9450,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                   = 9451,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                              = 9452,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                         = 9453,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE               = 9454,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                           = 9455,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                         = 9456,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                          = 9457,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY            = 9458,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                     = 9459,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                            = 9460,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                     = 9461,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                = 9462,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                              = 9463,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                          = 9464,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                            = 9465,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                = 9466,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                          = 9467,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                  = 9468,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                           = 9469,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                    = 9470,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                               = 9471,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                          = 9472,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                              = 9473,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                     = 9474,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        WELL_THAT_WAS_EXCITING_HM_YOU_RE_LOOKING                               = 9475,  -- Well, that was exciting... Hm? You're looking for that rude and crude little girl?
        WELL_WHY_DIDN_T_YOU_SAY_SO_WE                                          = 9476,  -- Well, why didn't you say so!? We thought she might go causing trouble, so...
        SO_WE_THREW_THE_VAGRANT_INTO_ONE_OF                                    = 9477,  -- So we threw the vagrant into one of our holding cells.
        LADY_CORNELIA_HAS_BEEN_KEEPING_THE_GIRL_COMPANY                        = 9478,  -- Lady Cornelia has been keeping the girl company. Master Cid, have you sustained any injuries?
        I_M_FINE_I_M_FINE_BUT_IT                                               = 9479,  -- I'm fine. I'm fine. But it's our little guest that I'm worried about. She seems pretty confused and upset. I was going to let her rest a while before I tried talking to her.
        OH_DON_T_WORRY_SHE_HASN_T_DONE                                         = 9480,  -- Oh, don't worry. She hasn't done anything wrong, and there are no plans of punishing her any further.
        SHE_LL_BE_LET_GO_ONCE_WE_VE                                            = 9481,  -- She'll be let go once we've sorted a few things out... Do you know what she was yelling about earlier?
        ALL_THIS_NONSENSE_ABOUT_AIRSHIPS_AND_WYRMKINGS_I                       = 9482,  -- All this nonsense about airships and Wyrmkings... I couldn't make heads or tails of it...
        WHAT_ARMORED_AIRSHIPS_HOODED_SCIENTISTS                                = 9483,  -- What!? Armored airships? Hooded scientists?
        WELL_THE_SCIENTISTS_ARE_PROBABLY_THE_ONES_FROM                         = 9484,  -- Well... The scientists are probably the ones from Jeuno. As for the airships, all I can think is that they might be the ones modified for battle during the Great War. But that project was canceled after the allied forces defeated the Shadow Lord's armies.
        I_KNOW_BECAUSE_I_WAS_A_MEMBER_OF                                       = 9485,  -- I know because I was a member of the project!
        TWENTY_YEARS_AGO_I_GET_THIS_INVITATION_FROM                            = 9486,  -- Twenty years ago, I get this invitation from the duke himself to work on a secret project for the Duchy. Minus myself and a few other scientists from Windurst, all the rest of the people assigned to the project are these creepy, pale-faced men in dark, hooded robes.
        THEY_RARELY_SHOWED_THEIR_FACES_IN_PUBLIC_BUT                           = 9487,  -- They rarely showed their faces in public, but from what I saw, the knowledge and technology they possessed was far superior to anything I had ever seen anywhere on Vana'diel.
        WHY_THE_CRYSTAL_PROPULSION_UNIT_THAT_THEY_HAD                          = 9488,  -- Why, the crystal propulsion unit that they had developed was years ahead of its time.
        BUT_IT_REQUIRED_AN_ENERGY_SOURCE_MORE_POWERFUL                         = 9489,  -- But it required an energy source more powerful than that which the eight elemental crystals found on Vana'diel could provide.
        WHAT_WERE_THE_JEUNOAN_SCIENTISTS_USING_TO_POWER                        = 9490,  -- What were the Jeunoan scientists using to power their unit, and where did they discover that power?
        I_WAS_DETERMINED_TO_FIND_OUT_SO_I                                      = 9491,  -- I was determined to find out, so I started watching them every chance I got.
        IT_WASN_T_LONG_BEFORE_I_NOTICED_THAT                                   = 9492,  -- It wasn't long before I noticed that they were conducting a lot of strange experiments around the Crag of [Holla/Dem/Mea], but I couldn't put my finger on exactly what they were doing...
        AND_NOW_THEY_VE_RESTARTED_THE_PROJECT_BUT                              = 9493,  -- And now they've restarted the project! But why are they sending the airships to Tavnazia...?
        TO_CATCH_BAHAMUT_THAT_S_WHY                                            = 9494,  -- To catch Bahamut, that's why!
        ID_9495                                                                = 9495,  -- !?
        CID_THIS_IS_PRISHE_SHE_S_FEELING_MUCH                                  = 9496,  -- Cid, this is Prishe. She's feeling much better than she was before. I think she's ready to talk.
        THANKS_CORNELIA_SO_PRISHE_FIRST_LET_ME_APOLOGIZE                       = 9497,  -- Thanks, Cornelia. So, Prishe. First, let me apologize for keeping you locked up for so long. No hard feelings, alright? But I need you to tell me, who is this Bahamut you keep talking about?
        OH_YOU_MEAN_THE_WYRMKING_WELL_EVERYTHING_WAS                           = 9498,  -- Oh, you mean the Wyrmking. Well, everything was all fine and dandy until one day, all of a sudden, this huge dragon appears over my hometown.
        WE_WERE_GOING_TO_MEET_THIS_DRAGON_AND                                  = 9499,  -- We were going to meet this dragon and try to knock some sense into him when out of nowhere, a huge airship contraption with all these guns and cannons flies up.
        WE_WERE_RIGHT_IN_THE_MIDDLE_OF_GIVING                                  = 9500,  -- We were right in the middle of giving the guys from that ship a sound beating until poof, I'm warped to this hellhole.
        WHAT_YOU_WERE_ACTUALLY_FIGHTING_AGAINST_THE_DUCHY                      = 9501,  -- What!? You were actually fighting against the Duchy?
        HEY_WE_WEREN_T_JUST_GOING_TO_SIT                                       = 9502,  -- Hey, we weren't just going to sit there and let them kill Bahamut! Anyway, it was Jeuno who took the first shots.
        IF_I_ONLY_HAD_A_LITTLE_MORE_TIME                                       = 9503,  -- If I only had a little more time, I could have found out what the Wyrmking meant when he was talking about the Keeper of the Apocalypse...
        KEEPER_OF_THE_APOCALYPSE_I_VE_HEARD_THAT                               = 9504,  -- Keeper of the Apocalypse... I've heard that name somewhere before...
        HMMM_I_M_NOT_SURE_WHAT_IT_IS                                           = 9505,  -- Hmmm... I'm not sure what it is exactly, but I can sense that something big is going down.
        AT_THE_SAME_TIME_THAT_THE_TELEPOINT_AT                                 = 9506,  -- At the same time that the Telepoint at Dem shattered, I heard a report of a giant dragon appearing over the sea north of Jeuno.
        IF_THAT_DRAGON_WAS_ACTUALLY_BAHAMUT_THEN_WE                            = 9507,  -- If that dragon was actually Bahamut, then we can conclude that the two events are in some way connected.
        THEN_THAT_S_ALL_THE_MORE_REASON_TO                                     = 9508,  -- Then that's all the more reason to get back to Riverne and try meeting with the Wyrmking one more time! C'mon, let's head for Jeuno!
        JEUNO_AFTER_ALL_THAT_S_HAPPENED_WHY_WOULD                              = 9509,  -- Jeuno? After all that's happened, why would you want to go there?
        I_VE_GOT_AN_OLD_FRIEND_WHO_WORKS                                       = 9510,  -- I've got an old friend who works at the Tenshodo. If I ask him, he'll be more than happy to ready a boat back to Tavnazia.
        WELL_I_LL_BE_SEEING_YOU_GUYS_AROUND                                    = 9511,  -- Well, I'll be seeing you guys around! Thanks for all the hospitality!
        HEY_WAIT_HOW_DO_YOU_PLAN_ON_TRAVELING                                  = 9512,  -- Hey, wait! How do you plan on traveling to Jeuno? Do you even know how far it is!?
        BAHAMUT_TAVNAZIA                                                       = 9513,  -- Bahamut... Tavnazia...
        MY_EARS_STILL_DOUBT_THE_CONVERSATION_I_JUST                            = 9514,  -- My ears still doubt the conversation I just heard. Could it all be true?
        I_GUESS_THE_ONLY_WAY_TO_FIND_OUT                                       = 9515,  -- I guess the only way to find out would be to tag along with that Prishe a little while longer. She said she was going to Jeuno to meet a friend... Who do you suppose she knows in the Duchy?
        THE_MULTINATIONAL_EXPEDITION_YEAH_I_REMEMBER_READING_ABOUT             = 9516,  -- The Multinational Expedition? Yeah, I remember reading about that in grade school, but if you want details, you'll have to ask someone a little bit older.
        CHIEF_CID_S_PRETTY_OLD_UH_OH_YOU                                       = 9517,  -- Chief Cid's pretty old... Uh-oh... You don't go telling him I said that, okay?
        YOU_WILL_FIND_THERE_ARE_NOT_MANY_PEOPLE                                = 9518,  -- You will find there are not many people who are willing to speak of the Multinational Expedition.
        ESPECIALLY_AMONG_US_GALKA                                              = 9519,  -- Especially among us Galka...
        WHAT_YOU_WANT_TO_HEAR_ABOUT_THE_MULTINATIONAL                          = 9520,  -- What, you want to hear about the Multinational Expedition?
        WHAT_IS_THERE_TO_KNOW_EVERYBODY_THAT_WENT                              = 9521,  -- What is there to know? Everybody that went on that damned mission passed away or was...
        I_USUALLY_DON_T_BELIEVE_IN_ANYTHING_CRAZY                              = 9522,  -- I usually don't believe in anything crazy like magic or curses, but after hearing the stories about what happened up there in the Northlands, I don't think there may be any other explanation.
        YOU_ALREADY_HEARD_FROM_THE_OTHER_TWO_NATIONS                           = 9523,  -- You already heard from the other two nations that the expedition was formed on the suggestion of the Republic, right?
        SIGH_MAYBE_IT_S_TIME_THAT_I_FACE                                       = 9524,  -- <Sigh> Maybe it's time that I face up to my past crimes... I was the one that pressured the government into sending a party to the Northlands.
        THIRTY_YEARS_AGO_A_MAN_BROUGHT_A_STRANGE                               = 9525,  -- Thirty years ago, a man brought a strange stone to the Metalworks.
        IT_WASN_T_ANY_BIGGER_THAN_MY_FIST                                      = 9526,  -- It wasn't any bigger than my fist, but just by standing near it you could feel the power flowing from its facets.
        THAT_POWER_WAS_GREATER_THAN_THAT_OF_ANY                                = 9527,  -- That power was greater than that of any crystal I had ever seen. I was shocked and amazed by what lay before my eyes.
        WHEN_THE_MAN_TOLD_ME_THAT_IT_WAS                                       = 9528,  -- When the man told me that it was a fragment of a crystal that was found in the Northlands, I was convinced that something more was hiding up there.
        I_THOUGHT_IF_I_COULD_FIND_THAT_ENERGY                                  = 9529,  -- I thought if I could find that energy source and bring it back to Bastok, the Republic would thrive, ultimately becoming the strongest, most advanced nation in the world.
        SO_I_TOLD_MY_DISCOVERY_TO_THE_PRESIDENT                                = 9530,  -- So I told my discovery to the president at the time, and suggested that he ready an expedition led by a party of musketeers.
        IT_WAS_SUPPOSED_TO_BE_TOP_SECRET_BUT                                   = 9531,  -- It was supposed to be top-secret, but somehow the information leaked to the other two nations, and...
        AND_IN_THE_END_THE_EXPEDITION_TURNED_UP                                = 9532,  -- And in the end, the expedition turned up nothing, and we lost more than we could ever have imagined...
        NOW_THAT_I_THINK_OF_IT_THE_ENERGY                                      = 9533,  -- Now that I think of it, the energy from that stone might have been enough to power the crystal propulsion unit.
        COULD_JEUNO_HAVE_ALREADY_FOUND_A_NEW_SOURCE                            = 9534,  -- Could Jeuno have already found a new source of energy in the Northlands?
        IF_I_ONLY_HAD_THAT_ROCK_UNFORTUNATELY_IT                               = 9535,  -- If I only had that rock... Unfortunately, it disappeared thirty years ago...right around the time of the expedition.
        THE_MAN_WHO_SOLD_ME_THE_STONE_A                                        = 9536,  -- The man who sold me the stone--a stone which he called magicite--said that he brought it from Tavnazia, and that it was a piece of a larger gem known as the Star of Tavnazia.
        MAYBE_THAT_CRAZY_BLUE_HAIRED_GIRL_FROM_THE                             = 9537,  -- Maybe that crazy blue-haired girl from the island knows something about that gem.
        DO_YOU_THINK_YOU_COULD_ASK_HER_FOR                                     = 9538,  -- Do you think you could ask her for me?
        SO_YOU_HAVE_A_PIECE_OF_THE_MAGICITE                                    = 9539,  -- So you have a piece of the magicite as well...
        IT_LOOKS_SIMILAR_TO_THE_ONE_I_SAW                                      = 9540,  -- It looks similar to the one I saw before, but I don't feel the same kind of power flowing from it.
        NO_THE_ONE_I_SAW_WAS_PITCH_BLACK                                       = 9541,  -- No, the one I saw was pitch-black and so powerful that you could feel its energy from over twenty yalms away.
        THE_MULTINATIONAL_EXPEDITION_HELD_THIRTY_YEARS_AGO_ALL                 = 9542,  -- The Multinational Expedition held thirty years ago all started when a shard of the fabled Star of Tavnazia was brought to the Republic.
        IT_WAS_RUMORED_THAT_THE_GEM_WAS_ORIGINALLY                             = 9543,  -- It was rumored that the gem was originally found in the Northlands, and that is why the party headed there first.
        IF_YOU_ASK_ONE_OF_YOUR_TAVNAZIAN_FRIENDS                               = 9544,  -- If you ask one of your Tavnazian friends about the star, you might be able to learn something interesting.
        OH_WHAT_ARE_YOU_DOING_HERE                                             = 9545,  -- Oh, %. What are you doing here?
        I_HEARD_THAT_YOU_WENT_BACK_TO_TAVNAZIA                                 = 9546,  -- I heard that you went back to Tavnazia. Did you already meet up with Louverance?
        HOW_DID_YOU_GET_OFF_THE_ISLAND                                         = 9547,  -- %! How did you get off the island!?
        AH_IT_S_CID                                                            = 9548,  -- Ah! It's Cid!
