        I_HAD_FAITH_IN_YOU_AND_YOU_TRULY                                       = 11007,  -- I had faith in you, %, and you truly shone brightly.
        A_FITTING_CONCLUSION_GIVEN_ALL_WE_HAVE_BEEN                            = 11008,  -- A fitting conclusion, given all we have been through. Now you know what it is like to have a true bond with someone.
