        I_VOLKER_SERVE_THE_MYTHRIL_MUSKETEERS_AS_ITS                           = 11013,  -- I, Volker, serve the Mythril Musketeers as its captain.
        I_HEREBY_PERMIT_YOU_TO_ENGAGE_IN_THE                                   = 11014,  -- I hereby permit you to engage in the Trust ritual with me.
        BUT_FIRST_A_WORD_OF_WARNING_AYAME_AND                                  = 11015,  -- But first, a word of warning. Ayame and Naji always complain that I am prone to giving boring lectures. My alter ego, naturally, would be cut from the same cloth. Are you still sure you wish to engage in this bonding nevertheless?
