        WHENEVER_I_LOOK_BACK_ON_WHAT_TRANSPIRED_THERE                          = 11026,  -- Whenever I look back on what transpired there, I cannot help but see your face.
        ANOTHER_REASON_WHY_I_HAVE_SO_MUCH_TRUST                                = 11027,  -- Another reason why I have so much trust in you is your long list of exploits in Aht Urhgan.
