        ON_THE_SURFACE_IT_DOES_NOT_SEEM_PARTICULARLY                           = 11060,  -- On the surface, it does not seem particularly dangerous...
        OH_HO_YOU_HAVE_BROUGHT_ALONG_THIS_CAN                                  = 11061,  -- Oh ho. You have brought along %. This can only mean one thing--you wish to try the ritual with me.
        NAJI_AND_AYAME_HAVE_BEEN_BLUSTERING_ALL_ABOUT                          = 11062,  -- Naji and Ayame have been blustering all about it for weeks. It's fun. You should try it!
        VOLKER_FOR_HIS_PART_HAS_REMAINED_LARGELY_SILENT                        = 11063,  -- Volker, for his part, has remained largely silent...but his gaze weighs heavy on my shoulders.
        I_CANNOT_HELP_BUT_THINK_IS_THERE_A                                     = 11064,  -- I cannot help but think--is there a need for every Mythril Musketeer, down to a man, to participate?
        AND_WHAT_IF_IT_PROVES_MORE_SINISTER_THAN                               = 11065,  -- And what if it proves more sinister than it seems at first glance? It could bring down our entire group!
        THEREFORE_AS_THE_SECOND_IN_COMMAND_I_FELT                              = 11066,  -- Therefore, as the second in command, I felt it was my duty to refrain.
        BUT_NOW_WITH_THE_OTHERS_ON_MY_CASE                                     = 11067,  -- But now, with the others on my case, it is time for me to search for an appropriate partner.
        YOU_SUGGEST_THAT_I_TRY_IT_WITH_ONE                                     = 11068,  -- ... You suggest that I try it with one of those three!?
        HAVE_YOU_NOT_HEARD_A_SINGLE_WORD_I                                     = 11069,  -- Have you not heard a single word I have said? I am completely fed up with them!
        IT_WOULD_BE_A_HUNDREDFOLD_LESS_PAINFUL_IF                              = 11070,  -- It would be a hundredfold less painful if it were with someone like you!
